import { useState, useEffect, useCallback } from 'react'
import { Box, Button, Group } from '@mantine/core'
import { notifications } from '@mantine/notifications'
import ThumbnailPanel from './ThumbnailPanel'
import DetailPanel from '../DetailPanel'
import { OpenPDF, PageCount, PickFolder, ExportSplit } from '../../../wailsjs/go/main/App'

interface Props {
  initialPath?: string | null
}

export default function SplitMode({ initialPath }: Props) {
  const [pdfPath, setPdfPath] = useState<string | null>(null)
  const [pageCount, setPageCount] = useState(0)
  const [selectedPage, setSelectedPage] = useState(1)
  const [splitPoints, setSplitPoints] = useState<Set<number>>(new Set())
  const [exporting, setExporting] = useState(false)

  useEffect(() => {
    if (!initialPath) return
    PageCount(initialPath)
      .then(count => {
        setPdfPath(initialPath)
        setPageCount(count)
        setSelectedPage(1)
        setSplitPoints(new Set())
      })
      .catch(e => notifications.show({ title: 'Failed to open file', message: String(e), color: 'red' }))
  }, [initialPath])

  const handleOpen = async () => {
    const path = await OpenPDF()
    if (!path) return
    try {
      const count = await PageCount(path)
      setPdfPath(path)
      setPageCount(count)
      setSelectedPage(1)
      setSplitPoints(new Set())
    } catch (e) {
      notifications.show({ title: 'Failed to open file', message: String(e), color: 'red' })
    }
  }

  const handleExport = async () => {
    if (!pdfPath) return
    const outDir = await PickFolder()
    if (!outDir) return
    setExporting(true)
    try {
      const sorted = [...splitPoints].sort((a, b) => a - b)
      await ExportSplit(pdfPath, sorted, outDir)
      const fileCount = splitPoints.size + 1
      notifications.show({
        title: 'Export complete',
        message: `${fileCount} file${fileCount !== 1 ? 's' : ''} saved to ${outDir}`,
        color: 'green',
      })
    } catch (e) {
      notifications.show({ title: 'Export failed', message: String(e), color: 'red' })
    } finally {
      setExporting(false)
    }
  }

  const toggleSplitPoint = useCallback((afterPage: number) => {
    setSplitPoints(prev => {
      const next = new Set(prev)
      if (next.has(afterPage)) {
        next.delete(afterPage)
      } else {
        next.add(afterPage)
      }
      return next
    })
  }, [])

  return (
    <Box style={{ display: 'flex', flexDirection: 'column', height: '100%' }}>
      <Box
        style={{
          flexShrink: 0,
          borderBottom: '1px solid var(--mantine-color-gray-3)',
          display: 'flex',
          alignItems: 'center',
          paddingInline: 12,
          height: 44,
        }}
      >
        <Group gap={8} style={{ width: '100%', justifyContent: 'space-between' }}>
          <Button size="xs" variant="default" onClick={handleOpen}>
            Open PDF
          </Button>
          <Button
            size="xs"
            disabled={!pdfPath}
            loading={exporting}
            onClick={handleExport}
          >
            Export
          </Button>
        </Group>
      </Box>

      <Box style={{ flex: 1, overflow: 'hidden', display: 'flex' }}>
        {pdfPath ? (
          <>
            <ThumbnailPanel
              pdfPath={pdfPath}
              pageCount={pageCount}
              selectedPage={selectedPage}
              onSelectPage={setSelectedPage}
              splitPoints={splitPoints}
              onToggleSplitPoint={toggleSplitPoint}
            />
            <DetailPanel
              pdfPath={pdfPath}
              pageNum={selectedPage}
              pageCount={pageCount}
              onNavigate={setSelectedPage}
            />
          </>
        ) : (
          <Box style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <Button onClick={handleOpen}>Open PDF</Button>
          </Box>
        )}
      </Box>
    </Box>
  )
}

import { useRef, useState, useEffect } from 'react'
import { useVirtualizer } from '@tanstack/react-virtual'
import { Loader } from '@mantine/core'
import * as pageCache from '../../hooks/pageCache'
import { DEFAULT_WIDTH, DRAG_HANDLE_WIDTH, ITEM_PADDING, PAGE_ASPECT, LABEL_HEIGHT } from '../../constants'

const MIN_WIDTH = 120
const MAX_WIDTH = 480
const GAP_HEIGHT = 16

interface Props {
  pdfPath: string
  pageCount: number
  selectedPage: number
  onSelectPage: (page: number) => void
  splitPoints: Set<number>
  onToggleSplitPoint: (afterPage: number) => void
}

export default function SplitThumbnailPanel({
  pdfPath, pageCount, selectedPage, onSelectPage, splitPoints, onToggleSplitPoint,
}: Props) {
  const [panelWidth, setPanelWidth] = useState(DEFAULT_WIDTH)
  const [hoveredGap, setHoveredGap] = useState<number | null>(null)

  const thumbWidth = panelWidth - ITEM_PADDING * 2
  const thumbHeight = Math.round(thumbWidth * PAGE_ASPECT)
  const itemHeight = thumbHeight + LABEL_HEIGHT + ITEM_PADDING + GAP_HEIGHT

  const scrollRef = useRef<HTMLDivElement>(null)

  const virtualizer = useVirtualizer({
    count: pageCount,
    getScrollElement: () => scrollRef.current,
    estimateSize: () => itemHeight,
    overscan: 3,
  })

  useEffect(() => {
    virtualizer.measure()
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [itemHeight])

  const virtualItems = virtualizer.getVirtualItems()
  pageCache.usePageCacheRender()

  useEffect(() => {
    for (const item of virtualItems) pageCache.load(pdfPath, item.index + 1, thumbWidth)
  })

  useEffect(() => {
    virtualizer.scrollToIndex(selectedPage - 1, { align: 'auto' })
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [selectedPage])

  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return
      if (e.key === 'ArrowLeft') {
        e.preventDefault()
        if (selectedPage > 1) onSelectPage(selectedPage - 1)
      } else if (e.key === 'ArrowRight') {
        e.preventDefault()
        if (selectedPage < pageCount) onSelectPage(selectedPage + 1)
      }
    }
    window.addEventListener('keydown', handler)
    return () => window.removeEventListener('keydown', handler)
  }, [selectedPage, pageCount, onSelectPage])

  const startDrag = (e: React.MouseEvent) => {
    const startX = e.clientX
    const startWidth = panelWidth
    const clamp = (w: number) => Math.max(MIN_WIDTH, Math.min(MAX_WIDTH, w))
    const onMove = (ev: MouseEvent) => setPanelWidth(clamp(startWidth + ev.clientX - startX))
    const onUp = (ev: MouseEvent) => {
      setPanelWidth(clamp(startWidth + ev.clientX - startX))
      document.removeEventListener('mousemove', onMove)
      document.removeEventListener('mouseup', onUp)
    }
    document.addEventListener('mousemove', onMove)
    document.addEventListener('mouseup', onUp)
    e.preventDefault()
  }

  return (
    <div style={{ display: 'flex', height: '100%', flexShrink: 0 }}>
      <div style={{ display: 'flex', flexDirection: 'column', width: panelWidth, height: '100%' }}>
        <div
          ref={scrollRef}
          style={{
            flex: 1,
            minHeight: 0,
            overflowY: 'auto',
            overflowX: 'hidden',
            background: 'var(--mantine-color-gray-3)',
          }}
        >
          <div style={{ height: virtualizer.getTotalSize(), position: 'relative' }}>
            {virtualItems.map(item => {
              const page = item.index + 1
              const src = pageCache.getSrc(pdfPath, page)
              const isSelected = page === selectedPage
              const isSplit = splitPoints.has(page)
              const isLastPage = page === pageCount

              return (
                <div
                  key={item.key}
                  style={{
                    position: 'absolute',
                    top: item.start,
                    left: 0,
                    width: '100%',
                    height: item.size,
                    boxSizing: 'border-box',
                  }}
                >
                  {/* Thumbnail */}
                  <div
                    style={{ padding: ITEM_PADDING, paddingBottom: 0, cursor: 'pointer' }}
                    onClick={() => onSelectPage(page)}
                  >
                    <div
                      style={{
                        border: `2px solid ${isSelected ? 'var(--mantine-color-blue-5)' : 'transparent'}`,
                        borderRadius: 4,
                        overflow: 'hidden',
                        background: 'var(--mantine-color-gray-1)',
                      }}
                    >
                      {src ? (
                        <img
                          src={src}
                          alt={`Page ${page}`}
                          style={{ width: '100%', display: 'block' }}
                          draggable={false}
                        />
                      ) : (
                        <div
                          style={{
                            width: '100%',
                            height: thumbHeight,
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: 'center',
                          }}
                        >
                          {pageCache.isLoading(pdfPath, page) && <Loader size="xs" />}
                        </div>
                      )}
                    </div>
                    <div
                      style={{
                        textAlign: 'center',
                        fontSize: 11,
                        color: 'var(--mantine-color-gray-7)',
                        height: LABEL_HEIGHT,
                        lineHeight: `${LABEL_HEIGHT}px`,
                      }}
                    >
                      {page}
                    </div>
                  </div>

                  {/* Gap zone between thumbnails */}
                  {!isLastPage && (
                    <GapZone
                      isSplit={isSplit}
                      isHovered={hoveredGap === page}
                      onClick={(e) => { e.stopPropagation(); onToggleSplitPoint(page) }}
                      onMouseEnter={() => setHoveredGap(page)}
                      onMouseLeave={() => setHoveredGap(null)}
                    />
                  )}
                </div>
              )
            })}
          </div>
        </div>
      </div>

      <div
        onMouseDown={startDrag}
        style={{
          width: DRAG_HANDLE_WIDTH,
          height: '100%',
          cursor: 'col-resize',
          flexShrink: 0,
          background: 'var(--mantine-color-gray-3)',
        }}
      />
    </div>
  )
}

interface GapZoneProps {
  isSplit: boolean
  isHovered: boolean
  onClick: (e: React.MouseEvent) => void
  onMouseEnter: () => void
  onMouseLeave: () => void
}

function GapZone({ isSplit, isHovered, onClick, onMouseEnter, onMouseLeave }: GapZoneProps) {
  const bg = isSplit
    ? 'var(--mantine-color-blue-0)'
    : isHovered
    ? 'var(--mantine-color-gray-2)'
    : undefined

  return (
    <div
      onClick={onClick}
      onMouseEnter={onMouseEnter}
      onMouseLeave={onMouseLeave}
      style={{
        height: GAP_HEIGHT,
        background: bg,
        display: 'flex',
        alignItems: 'center',
        paddingLeft: ITEM_PADDING,
        paddingRight: ITEM_PADDING,
        cursor: 'pointer',
      }}
    >
      {isSplit && (
        <div style={{ flex: 1, height: 2, background: 'var(--mantine-color-blue-5)', borderRadius: 1 }} />
      )}
      {!isSplit && isHovered && (
        <div style={{ flex: 1, height: 0, borderTop: '1px dashed var(--mantine-color-gray-5)' }} />
      )}
    </div>
  )
}

